// src/auth/session.ts
import { db } from "../db/client";

export interface Session {
  id: string;
  userId: string;
  createdAt: number;
  expiresAt: number;
}

const SESSION_TTL_MS = 1000 * 60 * 60 * 8;

export async function createSession(userId: string): Promise<Session> {
  const now = Date.now();
  const s: Session = { id: randId(), userId, createdAt: now, expiresAt: now + SESSION_TTL_MS };
  await db.query(
    "INSERT INTO sessions(id,user_id,created_at,expires_at) VALUES($1,$2,$3,$4)",
    [s.id, s.userId, s.createdAt, s.expiresAt],
  );
  return s;
}

export async function rotateSession(oldId: string): Promise<Session | null> {
  const rows = await db.query(
    "SELECT user_id FROM sessions WHERE id=$1 AND expires_at > $2",
    [oldId, Date.now()],
  );
  if (!rows.length) return null;
  await db.query("DELETE FROM sessions WHERE id=$1", [oldId]);
  return createSession(rows[0].user_id);
}

export async function revokeAllForUser(userId: string): Promise<number> {
  const res = await db.query("DELETE FROM sessions WHERE user_id=$1", [userId]);
  return res.rowCount ?? 0;
}

function randId(): string {
  return Math.random().toString(36).slice(2);
}

