import type { Request, Response, NextFunction } from "express";
import { db } from "../db/client";
import { verifyAccessToken } from "./token.service";

export async function requireSession(req: Request, res: Response, next: NextFunction) {
  const sid = req.header("x-session-id");
  if (!sid) return res.status(401).json({ error: "missing session" });
  const rows = await db.query(
    "SELECT user_id FROM sessions WHERE id=$1 AND expires_at > $2",
    [sid, Date.now()],
  );
  if (!rows.length) return res.status(401).json({ error: "invalid or expired session" });
  (req as any).userId = rows[0].user_id;
  next();
}

export async function requireBearer(req: Request, res: Response, next: NextFunction) {
  const header = req.header("authorization") ?? "";
  const token = header.startsWith("Bearer ") ? header.slice(7) : "";
  if (!token) return res.status(401).json({ error: "missing bearer token" });
  const claims = await verifyAccessToken(token);
  if (!claims) return res.status(401).json({ error: "invalid token" });
  (req as any).userId = claims.sub;
  next();
}

