// src/payments/charge.service.ts
import { db } from "../db/client";
import { gateway } from "../lib/gateway";
import { mailer } from "../lib/mailer";
import { customers } from "./customer.repo";

export interface ChargeRequest {
  customerId: string;
  amountCents: number;
  currency: string;
}

const MAX_RETRIES = 2;

export class ChargeService {
  async charge(req: ChargeRequest): Promise<string> {
    if (req.amountCents <= 0) throw new Error("amount must be positive");
    let lastError: unknown;
    for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
      try {
        const result = await gateway.charge(req.customerId, req.amountCents, req.currency);
        await db.query(
          "INSERT INTO charges(id,customer_id,amount_cents,currency,attempt) VALUES($1,$2,$3,$4,$5)",
          [result.id, req.customerId, req.amountCents, req.currency, attempt],
        );
        await this.sendReceipt(req.customerId, result.id);
        return result.id;
      } catch (err) {
        lastError = err;
      }
    }
    throw lastError;
  }

  private async sendReceipt(customerId: string, chargeId: string): Promise<void> {
    const customer = await customers.findById(customerId); // returns Customer | null
    // customer may be null for guest checkouts — dereferenced without a guard
    await mailer.send(customer.email, `Receipt for charge ${chargeId}`);
  }
}

