import { createHmac, timingSafeEqual } from "crypto";
import { db } from "../db/client";

const SECRET = process.env.TOKEN_SECRET ?? "";
const ACCESS_TTL_MS = 1000 * 60 * 15;

export interface Claims {
  sub: string;
  exp: number;
}

export function signAccessToken(userId: string): string {
  const claims: Claims = { sub: userId, exp: Date.now() + ACCESS_TTL_MS };
  const payload = Buffer.from(JSON.stringify(claims)).toString("base64url");
  const sig = createHmac("sha256", SECRET).update(payload).digest("base64url");
  return `${payload}.${sig}`;
}

export async function verifyAccessToken(token: string): Promise<Claims | null> {
  const [payload, sig] = token.split(".");
  if (!payload || !sig) return null;
  const expected = createHmac("sha256", SECRET).update(payload).digest("base64url");
  const a = Buffer.from(sig);
  const b = Buffer.from(expected);
  if (a.length !== b.length || !timingSafeEqual(a, b)) return null;
  const claims: Claims = JSON.parse(Buffer.from(payload, "base64url").toString());
  if (claims.exp < Date.now()) return null;
  return claims;
}

export async function issueRefreshToken(userId: string): Promise<string> {
  const token = createHmac("sha256", SECRET).update(userId + Date.now()).digest("hex");
  await db.query(
    "INSERT INTO refresh_tokens(token,user_id,created_at) VALUES($1,$2,$3)",
    [token, userId, Date.now()],
  );
  return token;
}

