export function hashPassword(plain: string): string {
  const salt = randomBytes(16).toString("hex");
  const hash = scryptSync(plain, salt, 64).toString("hex");
  return `${salt}:${hash}`;
}

export function verifyPassword(plain: string, stored: string): boolean {
  const [salt, hash] = stored.split(":");
  if (!salt || !hash) return false;
  const candidate = scryptSync(plain, salt, 64).toString("hex");
  return timingSafeEqual(Buffer.from(candidate), Buffer.from(hash));
}

export async function startPasswordReset(email: string): Promise<void> {
  const rows = await db.query("SELECT id FROM users WHERE email=$1", [email]);
  if (!rows.length) return; // do not leak account existence
  const token = randomBytes(24).toString("hex");
  await db.query(
    "INSERT INTO password_resets(user_id,token,expires_at) VALUES($1,$2,$3)",
    [rows[0].id, token, Date.now() + 1000 * 60 * 30],
  );
  await mailer.send(email, `Reset your password: /reset?token=${token}`);
}

