import { db } from "../db/client";
import { gateway } from "../lib/gateway";

export class RefundService {
  async refund(chargeId: string, amountCents?: number): Promise<string> {
    const rows = await db.query("SELECT amount_cents, refunded_cents FROM charges WHERE id=$1", [chargeId]);
    if (!rows.length) throw new Error(`unknown charge ${chargeId}`);
    const remaining = rows[0].amount_cents - (rows[0].refunded_cents ?? 0);
    const toRefund = amountCents ?? remaining;
    if (toRefund <= 0 || toRefund > remaining) {
      throw new Error(`refund of ${toRefund} exceeds remaining ${remaining}`);
    }
    const result = await gateway.refund(chargeId, toRefund);
    await db.query(
      "UPDATE charges SET refunded_cents = COALESCE(refunded_cents,0) + $1 WHERE id=$2",
      [toRefund, chargeId],
    );
    return result.id;
  }
}

